import React from 'react';

const TopNavbar = ({ user, onLogout, activePage = 'departments' }) => {
    const capitalize = (str) => str.charAt(0).toUpperCase() + str.slice(1);

    return (
        <div className="top-navbar">
            <div className="navbar-left">
                <div className="breadcrumb">
                    Admin <span>&gt;</span> {capitalize(activePage)}
                </div>
            </div>
            <div className="navbar-right">
                <div className="live-badge-top">LIVE</div>
                <button className="icon-btn">🔔</button>
                <button className="profile-trigger" onClick={onLogout}>
                    <div className="avatar-sm">
                        {user?.role === 'admin' ? 'A' : 'U'}
                    </div>
                    {capitalize(user?.role || 'Admin')}
                </button>
            </div>
        </div>
    );
};

export default TopNavbar;
